def solve(age, heart_rate, systolic_bp, serum_creatinine, killip_class, cardiac_arrest, st_segment_deviation, elevated_cardiac_markers):
    # Step 1: calculate_age_score
    # Determine the age component score based on the patient's age.
    if age <= 30:
        age_score = 0
    elif 30 <= age <= 39:
        age_score = 8
    elif 40 <= age <= 49:
        age_score = 25
    elif 50 <= age <= 59:
        age_score = 41
    elif 60 <= age <= 69:
        age_score = 58
    elif 70 <= age <= 79:
        age_score = 75
    elif 80 <= age <= 89:
        age_score = 91
    else:  # age >= 90
        age_score = 100
    yield {
        "step_name": "calculate_age_score",
        "step_description": "Determine the age component score based on the patient's age.",
        "step_result": age_score,
        "unit": "points"
    }

    # Step 2: calculate_heart_rate_score
    # Determine the heart rate component score based on the patient's heart rate.
    if heart_rate <= 49:
        heart_rate_score = 0
    elif 50 <= heart_rate <= 69:
        heart_rate_score = 3
    elif 70 <= heart_rate <= 89:
        heart_rate_score = 9
    elif 90 <= heart_rate <= 109:
        heart_rate_score = 15
    elif 110 <= heart_rate <= 149:
        heart_rate_score = 24
    elif 150 <= heart_rate <= 199:
        heart_rate_score = 38
    else:  # heart_rate >= 200
        heart_rate_score = 46
    yield {
        "step_name": "calculate_heart_rate_score",
        "step_description": "Determine the heart rate component score based on the patient's heart rate.",
        "step_result": heart_rate_score,
        "unit": "points"
    }

    # Step 3: calculate_systolic_bp_score
    # Determine the systolic blood pressure component score based on the patient's systolic BP.
    if systolic_bp <= 79:
        systolic_bp_score = 58
    elif 80 <= systolic_bp <= 99:
        systolic_bp_score = 53
    elif 100 <= systolic_bp <= 119:
        systolic_bp_score = 43
    elif 120 <= systolic_bp <= 139:
        systolic_bp_score = 34
    elif 140 <= systolic_bp <= 159:
        systolic_bp_score = 24
    elif 160 <= systolic_bp <= 199:
        systolic_bp_score = 10
    else:  # systolic_bp >= 200
        systolic_bp_score = 0
    yield {
        "step_name": "calculate_systolic_bp_score",
        "step_description": "Determine the systolic blood pressure component score based on the patient's systolic BP.",
        "step_result": systolic_bp_score,
        "unit": "points"
    }

    # Step 4: calculate_creatinine_score
    # Determine the serum creatinine component score based on the patient's creatinine level.
    if 0 <= serum_creatinine <= 0.39:
        creatinine_score = 1
    elif 0.40 <= serum_creatinine <= 0.79:
        creatinine_score = 4
    elif 0.80 <= serum_creatinine <= 1.19:
        creatinine_score = 7
    elif 1.20 <= serum_creatinine <= 1.59:
        creatinine_score = 10
    elif 1.60 <= serum_creatinine <= 1.99:
        creatinine_score = 13
    elif 2.00 <= serum_creatinine <= 3.99:
        creatinine_score = 21
    else:  # serum_creatinine >= 4.0
        creatinine_score = 28
    yield {
        "step_name": "calculate_creatinine_score",
        "step_description": "Determine the serum creatinine component score based on the patient's creatinine level.",
        "step_result": creatinine_score,
        "unit": "points"
    }

    # Step 5: calculate_killip_score
    # Determine the Killip class component score based on the patient's Killip classification.
    if killip_class == 'I':
        killip_score = 0
    elif killip_class == 'II':
        killip_score = 20
    elif killip_class == 'III':
        killip_score = 39
    elif killip_class == 'IV':
        killip_score = 59
    else:
        raise ValueError("Invalid Killip class. Allowed values: 'I', 'II', 'III', 'IV'")
    yield {
        "step_name": "calculate_killip_score",
        "step_description": "Determine the Killip class component score based on the patient's Killip classification.",
        "step_result": killip_score,
        "unit": "points"
    }

    # Step 6: calculate_cardiac_arrest_score
    # Determine the cardiac arrest at admission component score.
    cardiac_arrest_score = 39 if cardiac_arrest else 0
    yield {
        "step_name": "calculate_cardiac_arrest_score",
        "step_description": "Determine the cardiac arrest at admission component score.",
        "step_result": cardiac_arrest_score,
        "unit": "points"
    }

    # Step 7: calculate_st_deviation_score
    # Determine the ST-segment deviation component score.
    st_deviation_score = 28 if st_segment_deviation else 0
    yield {
        "step_name": "calculate_st_deviation_score",
        "step_description": "Determine the ST-segment deviation component score.",
        "step_result": st_deviation_score,
        "unit": "points"
    }

    # Step 8: calculate_cardiac_markers_score
    # Determine the elevated cardiac markers component score.
    cardiac_markers_score = 14 if elevated_cardiac_markers else 0
    yield {
        "step_name": "calculate_cardiac_markers_score",
        "step_description": "Determine the elevated cardiac markers component score.",
        "step_result": cardiac_markers_score,
        "unit": "points"
    }

    # Step 9: calculate_total_grace_score
    # Sum all component scores to obtain the total GRACE 2.0 risk score.
    total_grace_score = age_score + heart_rate_score + systolic_bp_score + creatinine_score + killip_score + cardiac_arrest_score + st_deviation_score + cardiac_markers_score
    yield {
        "step_name": "calculate_total_grace_score",
        "step_description": "Sum all component scores to obtain the total GRACE 2.0 risk score.",
        "step_result": total_grace_score,
        "unit": "points"
    }

    return total_grace_score
